    high := b >> 4
    low := b & 0x0f
    var h, l byte
    if high < 10 {
        h = '0' + high
    } else {
        h = 'a' + high - 10
    }
    if low < 10 {
        l = '0' + low
    } else {
        l = 'a' + low - 10
    }
    return h, l
}
```

